from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return "."

    # Group triples by subject
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Extract all triples into a flat list with subject context
    all_triples = []
    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            all_triples.append((subject, predicate, obj))

    # Build a single, natural sentence from all triples
    # Use the first triple's subject as the main subject
    main_subject = triples[0].subject

    # First pass: extract location and country to resolve context
    location = None
    country = None
    for subject, predicate, obj in all_triples:
        if predicate == "location":
            location = obj
        elif predicate == "country":
            country = obj

    # Second pass: build sentence components with integrated context
    runway_details = []
    elevation_details = []
    identifier_details = []
    other_details = []

    for subject, predicate, obj in all_triples:
        if predicate == "cityServed":
            other_details.append(f"serves the city of {obj}")
        elif predicate == "mayor":
            other_details.append(f"has mayor {obj}")
        elif predicate == "isPartOf":
            other_details.append(f"is part of {obj}")
        elif predicate == "operatingOrganisation":
            other_details.append(f"is operated by {obj}")
        elif predicate == "location":
            if country and location != country:
                other_details.append(f"located in {obj}, {country}")
            else:
                other_details.append(f"located in {obj}")
        elif predicate == "elevationAboveTheSeaLevel":
            elevation_details.append(f"{obj} metres above sea level")
        elif predicate == "runwayLength":
            runway_details.append(f"runway length of {obj} metres")
        elif predicate == "country":
            # Already handled above; avoid duplication
            continue
        elif predicate == "capital":
            other_details.append(f"has capital {obj}")
        elif predicate == "language":
            other_details.append(f"where {obj} is spoken")
        elif predicate == "leader":
            other_details.append(f"is led by {obj}")
        elif predicate == "owner":
            other_details.append(f"is owned by {obj}")
        elif predicate == "1stRunwayLengthFeet":
            runway_details.append(f"first runway length of {obj} feet")
        elif predicate == "1stRunwaySurfaceType":
            runway_details.append(f"first runway surface: {obj}")
        elif predicate == "3rdRunwayLengthFeet":
            runway_details.append(f"third runway length of {obj} feet")
        elif predicate == "icaoLocationIdentifier":
            identifier_details.append(f"ICAO: {obj}")
        elif predicate == "locationIdentifier":
            identifier_details.append(f"location identifier: {obj}")
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            elevation_details.append(f"{obj} feet above sea level")
        elif predicate == "iataLocationIdentifier":
            identifier_details.append(f"IATA: {obj}")
        elif predicate == "nativeName":
            other_details.append(f"also known as {obj}")
        elif predicate == "leaderParty":
            other_details.append(f"led by party {obj}")
        elif predicate == "runwayName":
            other_details.append(f"has runway {obj}")
        elif predicate == "runwaySurfaceType":
            runway_details.append(f"runway surface: {obj}")
        elif predicate == "elevationAboveTheSeaLevelInMetres":
            elevation_details.append(f"{obj} metres above sea level")
        else:
            # Fallback for any unknown predicate
            other_details.append(f"has a {predicate} of {obj}")

    # Combine all details into one cohesive sentence
    parts = [main_subject]

    # Add elevation details
    if elevation_details:
        parts.append(f"with an elevation of {', '.join(elevation_details)}")

    # Add runway details
    if runway_details:
        parts.append(f"with {', '.join(runway_details)}")

    # Add identifier details
    if identifier_details:
        parts.append(f"with {', '.join(identifier_details)}")

    # Add other details
    if other_details:
        parts.append(f"which {', '.join(other_details)}")

    # Join all parts into one sentence
    result = " ".join(parts)

    # Ensure proper punctuation
    if not result.endswith("."):
        result += "."

    return result

